const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Pool } = require('pg');

const pool = new Pool({
  user: 'your_db_user',
  host: 'localhost',
  database: 'your_db_name',
  password: 'your_db_password',
  port: 5432,
});

const schema = buildSchema(`
  type Post {
    id: ID!
    title: String!
    content: String!
    author: Author!
  }

  type Author {
    id: ID!
    name: String!
  }

  type Query {
    posts: [Post]
  }
`);

const root = {
  posts: async () => {
    const client = await pool.connect();
    try {
      const res = await client.query('SELECT * FROM posts');
      return res.rows.map(async post => {
        const authorRes = await client.query('SELECT * FROM authors WHERE id = $1', [post.author_id]);
        return {
          ...post,
          author: authorRes.rows[0]
        };
      });
    } finally {
      client.release();
    }
  }
};

const app = express();

app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: false,
  customFormatErrorFn: (err) => ({
    message: err.message,
    locations: err.locations,
    path: err.path
  })
}));

app.listen(4000, () => console.log('Server running on http://localhost:4000/graphql'));